import { Link, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../features/auth/authSlice';

export default function Navbar() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector(s => s.auth.user);

  const handleLogout = () => { dispatch(logout()); navigate('/login'); };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>🍽 Grand Table</Link>
      <div style={styles.links}>
        {user ? (
          <>
            {user.role === 'customer' && <Link to="/reserve" style={styles.link}>Reserve</Link>}
            {user.role === 'customer' && <Link to="/my-reservations" style={styles.link}>My Bookings</Link>}
            {user.role === 'customer' && <Link to="/waitlist" style={styles.link}>Waitlist</Link>}
            {(user.role === 'staff' || user.role === 'admin') && <Link to="/dashboard" style={styles.link}>Dashboard</Link>}
            {user.role === 'admin' && <Link to="/admin" style={styles.link}>Admin</Link>}
            <span style={styles.name}>{user.name}</span>
            <button onClick={handleLogout} style={styles.btn}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <Link to="/register" style={styles.link}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

const styles = {
  nav:   { display:'flex', justifyContent:'space-between', alignItems:'center', padding:'12px 24px', background:'#1a1a2e', color:'#fff' },
  brand: { color:'#e94560', fontWeight:'bold', fontSize:'1.2rem', textDecoration:'none' },
  links: { display:'flex', gap:'16px', alignItems:'center' },
  link:  { color:'#eee', textDecoration:'none', fontSize:'0.95rem' },
  name:  { color:'#aaa', fontSize:'0.9rem' },
  btn:   { background:'#e94560', color:'#fff', border:'none', padding:'6px 14px', borderRadius:'4px', cursor:'pointer' },
};
